import { logger } from '@/lib/logger'
import { supabaseAdmin } from '@/lib/supabase/server'

interface CreditTransaction {
  userId: string;
  amount: number;
  type: 'deduct' | 'refund' | 'purchase';
  reason: string;
  balanceAfter: number;
}

export class CreditManager {
  /**
   * Check if user has enough credits
   */
  async hasCredits(userId: string, amount: number): Promise<boolean> {
    const balance = await this.getBalance(userId)
    return balance >= amount
  }

  /**
   * Get user credit balance from Supabase
   */
  async getBalance(userId: string): Promise<number> {
    try {
      const { data, error } = await (supabaseAdmin as unknown as { from: (t: string) => { select: (c: string) => { eq: (k: string, v: string) => { single: () => Promise<{ data: Record<string, unknown> | null; error: { code?: string; message?: string } | null }> } } } })
        .from('users')
        .select('credits')
        .eq('id', userId)
        .single()

      if (error) {
        if (error.code === 'PGRST116' || error.message?.includes('credits')) {
          logger.warn('Credits column not found, returning default', { userId })
          return 100
        }
        throw new Error(error.message)
      }

      return (data?.credits as number) ?? 100
    } catch (error: unknown) {
      logger.error('Failed to get credit balance', error as Error)
      return 100 // Graceful default
    }
  }

  /**
   * Deduct credits from user account with transaction logging
   */
  async deductCredits(userId: string, amount: number, reason: string): Promise<boolean> {
    try {
      const balance = await this.getBalance(userId)
      if (balance < amount) {
        logger.warn('Insufficient credits', { userId, balance, requested: amount })
        return false
      }

      const newBalance = balance - amount

      // Update user credits
      const supaUpdate = supabaseAdmin as unknown as { from: (t: string) => { update: (d: Record<string, unknown>) => { eq: (k: string, v: string) => Promise<{ error: { message?: string } | null }> } } }
      const { error: updateError } = await supaUpdate
        .from('users')
        .update({ credits: newBalance })
        .eq('id', userId)

      if (updateError) {
        if (updateError.message?.includes('credits')) {
          logger.warn('Credits column not available for update', { userId })
        } else {
          throw new Error(updateError.message)
        }
      }

      await this.logTransaction({
        userId,
        amount: -amount,
        type: 'deduct',
        reason,
        balanceAfter: newBalance,
      })

      logger.info(`Deducted ${amount} credits from user ${userId}`, { reason, newBalance })
      return true
    } catch (error: unknown) {
      logger.error('Failed to deduct credits', error as Error)
      return false
    }
  }

  /**
   * Refund credits (e.g. failed generation) with transaction logging
   */
  async refundCredits(userId: string, amount: number, reason: string): Promise<void> {
    try {
      const balance = await this.getBalance(userId)
      const newBalance = balance + amount

      const supaRefund = supabaseAdmin as unknown as { from: (t: string) => { update: (d: Record<string, unknown>) => { eq: (k: string, v: string) => Promise<{ error: { message?: string } | null }> } } }
      const { error: updateError } = await supaRefund
        .from('users')
        .update({ credits: newBalance })
        .eq('id', userId)

      if (updateError && !updateError.message?.includes('credits')) {
        throw new Error(updateError.message)
      }

      await this.logTransaction({
        userId,
        amount,
        type: 'refund',
        reason,
        balanceAfter: newBalance,
      })

      logger.info(`Refunded ${amount} credits to user ${userId}`, { reason, newBalance })
    } catch (error: unknown) {
      logger.error('Failed to refund credits', error as Error)
    }
  }

  /**
   * Log credit transaction to analytics_events for auditing
   */
  private async logTransaction(tx: CreditTransaction): Promise<void> {
    try {
      await supabaseAdmin.from('analytics_events').insert({
        event_type: `credits.${tx.type}`,
        user_id: tx.userId,
        event_data: {
          amount: tx.amount,
          reason: tx.reason,
          balanceAfter: tx.balanceAfter,
        },
        created_at: new Date().toISOString(),
      })
    } catch (error: unknown) {
      // Non-blocking: don't fail the operation if logging fails
      logger.warn('Failed to log credit transaction', { error: (error as Error).message })
    }
  }
}
